import React, { useState, useEffect } from 'react';
import { Mic, MicOff, Send, Pause, Play, Volume2, VolumeX, User, Bot, MessageSquare, FileText, BookOpen } from 'lucide-react';

interface Message {
  id: number;
  sender: 'user' | 'ai' | 'system';
  content: string;
  timestamp: Date;
}

interface Document {
  _id: string;
  name: string;
  type: 'contract' | 'evidence' | 'pleading' | 'correspondence';
  pages: number;
}

const CourtroomSimulation: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 1,
      sender: 'system',
      content: 'Welcome to the CourtCraft courtroom simulation. You are representing the plaintiff in a contract dispute case.',
      timestamp: new Date()
    },
    {
      id: 2,
      sender: 'ai',
      content: 'Good morning, Counsel. I am Judge Sharma presiding over this matter. Please present your opening statement.',
      timestamp: new Date()
    }
  ]);
  const [inputMessage, setInputMessage] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [activeTab, setActiveTab] = useState<'chat' | 'documents' | 'notes'>('chat');
  const [documents, setDocuments] = useState<Document[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Fetch documents from backend
  useEffect(() => {
    const fetchDocuments = async () => {
      try {
        setLoading(true);
        
        // In a real implementation, we would fetch data from the backend
        // For now, we'll use mock data but simulate an API call
        await new Promise(resolve => setTimeout(resolve, 1000));
        
        const mockDocuments: Document[] = [
          { _id: "1", name: 'Contract Agreement.pdf', type: 'contract', pages: 12 },
          { _id: "2", name: 'Email Correspondence.pdf', type: 'correspondence', pages: 3 },
          { _id: "3", name: 'Witness Statements.pdf', type: 'evidence', pages: 8 },
          { _id: "4", name: 'Motion for Summary Judgment.pdf', type: 'pleading', pages: 5 }
        ];
        
        setDocuments(mockDocuments);
        setLoading(false);
      } catch (err) {
        setError('Error fetching documents: ' + (err as Error).message);
        console.error('Error fetching documents:', err);
        setLoading(false);
      }
    };

    fetchDocuments();
  }, []);

  const handleSendMessage = () => {
    if (inputMessage.trim() === '') return;
    
    const newMessage: Message = {
      id: messages.length + 1,
      sender: 'user',
      content: inputMessage,
      timestamp: new Date()
    };
    
    setMessages([...messages, newMessage]);
    setInputMessage('');
    
    // Simulate AI response after a delay
    setTimeout(() => {
      const aiResponse: Message = {
        id: messages.length + 2,
        sender: 'ai',
        content: "Thank you for that statement, Counsel. The defendant would like to respond to your claims. Mr. Advocate for the defense, please present your counter-argument.",
        timestamp: new Date()
      };
      setMessages(prev => [...prev, aiResponse]);
    }, 2000);
  };

  const toggleRecording = () => {
    setIsRecording(!isRecording);
  };

  const toggleMute = () => {
    setIsMuted(!isMuted);
  };

  const getDocumentIcon = (type: string) => {
    switch (type) {
      case 'contract': return <FileText className="w-5 h-5 text-blue-500" />;
      case 'evidence': return <FileText className="w-5 h-5 text-green-500" />;
      case 'pleading': return <FileText className="w-5 h-5 text-purple-500" />;
      case 'correspondence': return <FileText className="w-5 h-5 text-yellow-500" />;
      default: return <FileText className="w-5 h-5 text-gray-500" />;
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="inline-block animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
          <p className="text-gray-600">Loading courtroom simulation...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center py-12">
          <div className="bg-red-100 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4">
            <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path>
            </svg>
          </div>
          <h3 className="text-xl font-bold text-gray-900 mb-2">Error Loading Courtroom Simulation</h3>
          <p className="text-gray-600 mb-4">{error}</p>
          <button 
            className="bg-indigo-600 text-white px-6 py-3 rounded-lg hover:bg-indigo-700 transition duration-300 font-medium"
            onClick={() => window.location.reload()}
          >
            Try Again
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white shadow-sm">
        <div className="container mx-auto px-4 py-4">
          <div className="flex justify-between items-center">
            <div>
              <h1 className="text-2xl font-bold text-gray-900">Contract Dispute Case</h1>
              <p className="text-gray-600">Plaintiff vs. Defendant - Civil Court, Delhi</p>
            </div>
            <div className="flex items-center space-x-4">
              <div className="flex items-center bg-red-100 text-red-800 px-3 py-1 rounded-full">
                <div className="w-2 h-2 bg-red-500 rounded-full mr-2 animate-pulse"></div>
                <span className="text-sm font-medium">Recording</span>
              </div>
              <button className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition duration-300">
                End Session
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Main Courtroom Area */}
          <div className="lg:col-span-2">
            <div className="bg-white rounded-xl shadow-sm overflow-hidden">
              {/* Courtroom Visualization */}
              <div className="bg-gradient-to-b from-amber-800 to-amber-900 h-64 relative">
                <div className="absolute inset-0 flex items-center justify-center">
                  {/* Judge's Bench */}
                  <div className="bg-amber-700 w-64 h-24 rounded-lg flex items-center justify-center shadow-lg">
                    <div className="text-center">
                      <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center mx-auto mb-2">
                        <User className="w-6 h-6 text-amber-800" />
                      </div>
                      <p className="text-white font-medium">Hon. Judge Sharma</p>
                      <p className="text-amber-200 text-sm">Presiding</p>
                    </div>
                  </div>
                  
                  {/* Plaintiff Table */}
                  <div className="absolute left-8 bottom-8 bg-amber-100 w-48 h-20 rounded-lg flex items-center justify-center shadow">
                    <div className="text-center">
                      <div className="w-8 h-8 bg-indigo-600 rounded-full flex items-center justify-center mx-auto mb-1">
                        <User className="w-4 h-4 text-white" />
                      </div>
                      <p className="text-gray-900 font-medium text-sm">You (Plaintiff)</p>
                    </div>
                  </div>
                  
                  {/* Defendant Table */}
                  <div className="absolute right-8 bottom-8 bg-amber-100 w-48 h-20 rounded-lg flex items-center justify-center shadow">
                    <div className="text-center">
                      <div className="w-8 h-8 bg-red-600 rounded-full flex items-center justify-center mx-auto mb-1">
                        <Bot className="w-4 h-4 text-white" />
                      </div>
                      <p className="text-gray-900 font-medium text-sm">Defendant Counsel</p>
                    </div>
                  </div>
                </div>
              </div>
              
              {/* Chat Interface */}
              <div className="p-6">
                <div className="flex border-b border-gray-200 mb-6">
                  <button
                    className={`pb-3 px-4 font-medium ${activeTab === 'chat' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('chat')}
                  >
                    <MessageSquare className="w-5 h-5 inline mr-2" />
                    Conversation
                  </button>
                  <button
                    className={`pb-3 px-4 font-medium ${activeTab === 'documents' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('documents')}
                  >
                    <FileText className="w-5 h-5 inline mr-2" />
                    Documents
                  </button>
                  <button
                    className={`pb-3 px-4 font-medium ${activeTab === 'notes' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('notes')}
                  >
                    <BookOpen className="w-5 h-5 inline mr-2" />
                    Notes
                  </button>
                </div>
                
                {activeTab === 'chat' && (
                  <div className="space-y-6">
                    <div className="h-96 overflow-y-auto pr-2">
                      {messages.map(message => (
                        <div 
                          key={message.id} 
                          className={`mb-6 ${message.sender === 'user' ? 'text-right' : ''}`}
                        >
                          <div className="flex items-start">
                            {message.sender !== 'user' && (
                              <div className={`w-8 h-8 rounded-full flex items-center justify-center mr-3 flex-shrink-0 ${message.sender === 'ai' ? 'bg-red-100' : 'bg-gray-100'}`}>
                                {message.sender === 'ai' ? 
                                  <Bot className="w-5 h-5 text-red-600" /> : 
                                  <MessageSquare className="w-5 h-5 text-gray-600" />
                                }
                              </div>
                            )}
                            <div className={`max-w-3/4 rounded-2xl px-4 py-3 ${message.sender === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : message.sender === 'ai' ? 'bg-red-50 text-gray-900 rounded-tl-none' : 'bg-gray-100 text-gray-900 rounded-tl-none'}`}>
                              <p>{message.content}</p>
                              <p className={`text-xs mt-1 ${message.sender === 'user' ? 'text-indigo-200' : 'text-gray-500'}`}>
                                {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                              </p>
                            </div>
                            {message.sender === 'user' && (
                              <div className="w-8 h-8 bg-indigo-600 rounded-full flex items-center justify-center ml-3 flex-shrink-0">
                                <User className="w-5 h-5 text-white" />
                              </div>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>
                    
                    <div className="flex space-x-3">
                      <div className="flex-1 relative">
                        <input
                          type="text"
                          placeholder="Type your response..."
                          className="w-full pl-4 pr-12 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                          value={inputMessage}
                          onChange={(e) => setInputMessage(e.target.value)}
                          onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
                        />
                        <button 
                          className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 hover:text-gray-600"
                          onClick={toggleRecording}
                        >
                          {isRecording ? <MicOff className="w-5 h-5" /> : <Mic className="w-5 h-5" />}
                        </button>
                      </div>
                      <button 
                        className="bg-indigo-600 text-white p-3 rounded-lg hover:bg-indigo-700 transition duration-300"
                        onClick={handleSendMessage}
                      >
                        <Send className="w-5 h-5" />
                      </button>
                    </div>
                  </div>
                )}
                
                {activeTab === 'documents' && (
                  <div className="space-y-4">
                    <div className="flex justify-between items-center">
                      <h3 className="text-lg font-semibold text-gray-900">Case Documents</h3>
                      <button className="text-indigo-600 hover:text-indigo-800 font-medium">
                        Upload Document
                      </button>
                    </div>
                    
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {documents.map(doc => (
                        <div key={doc._id} className="border border-gray-200 rounded-lg p-4 hover:bg-gray-50 transition duration-300">
                          <div className="flex items-start">
                            <div className="mr-3 mt-1">
                              {getDocumentIcon(doc.type)}
                            </div>
                            <div className="flex-1">
                              <h4 className="font-medium text-gray-900">{doc.name}</h4>
                              <p className="text-sm text-gray-500">{doc.pages} pages</p>
                            </div>
                            <button className="text-indigo-600 hover:text-indigo-800">
                              <Play className="w-5 h-5" />
                            </button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
                
                {activeTab === 'notes' && (
                  <div>
                    <h3 className="text-lg font-semibold text-gray-900 mb-4">Session Notes</h3>
                    <textarea 
                      className="w-full h-64 p-4 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                      placeholder="Take notes during your session..."
                    ></textarea>
                    <div className="flex justify-end mt-3">
                      <button className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition duration-300">
                        Save Notes
                      </button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
          
          {/* Control Panel */}
          <div className="space-y-6">
            {/* Session Controls */}
            <div className="bg-white rounded-xl shadow-sm p-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Session Controls</h3>
              <div className="grid grid-cols-2 gap-4">
                <button className="flex flex-col items-center justify-center p-4 bg-gray-50 rounded-lg hover:bg-gray-100 transition duration-300">
                  <Pause className="w-6 h-6 text-gray-700 mb-2" />
                  <span className="text-sm font-medium text-gray-700">Pause</span>
                </button>
                <button 
                  className="flex flex-col items-center justify-center p-4 bg-gray-50 rounded-lg hover:bg-gray-100 transition duration-300"
                  onClick={toggleMute}
                >
                  {isMuted ? 
                    <VolumeX className="w-6 h-6 text-gray-700 mb-2" /> : 
                    <Volume2 className="w-6 h-6 text-gray-700 mb-2" />
                  }
                  <span className="text-sm font-medium text-gray-700">
                    {isMuted ? 'Unmute' : 'Mute'}
                  </span>
                </button>
              </div>
              
              <div className="mt-6">
                <h4 className="font-medium text-gray-900 mb-3">Session Timer</h4>
                <div className="text-3xl font-bold text-center py-4 bg-gray-50 rounded-lg">
                  24:18
                </div>
              </div>
            </div>
            
            {/* Performance Metrics */}
            <div className="bg-white rounded-xl shadow-sm p-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Performance Metrics</h3>
              <div className="space-y-4">
                <div>
                  <div className="flex justify-between mb-1">
                    <span className="text-sm font-medium text-gray-700">Argumentation</span>
                    <span className="text-sm font-medium text-gray-700">85%</span>
                  </div>
                  <div className="w-full bg-gray-200 rounded-full h-2">
                    <div className="bg-green-600 h-2 rounded-full" style={{ width: '85%' }}></div>
                  </div>
                </div>
                
                <div>
                  <div className="flex justify-between mb-1">
                    <span className="text-sm font-medium text-gray-700">Evidence Presentation</span>
                    <span className="text-sm font-medium text-gray-700">78%</span>
                  </div>
                  <div className="w-full bg-gray-200 rounded-full h-2">
                    <div className="bg-blue-600 h-2 rounded-full" style={{ width: '78%' }}></div>
                  </div>
                </div>
                
                <div>
                  <div className="flex justify-between mb-1">
                    <span className="text-sm font-medium text-gray-700">Courtroom Etiquette</span>
                    <span className="text-sm font-medium text-gray-700">92%</span>
                  </div>
                  <div className="w-full bg-gray-200 rounded-full h-2">
                    <div className="bg-purple-600 h-2 rounded-full" style={{ width: '92%' }}></div>
                  </div>
                </div>
              </div>
              
              <button className="w-full mt-6 bg-indigo-600 text-white py-2 rounded-lg hover:bg-indigo-700 transition duration-300">
                View Detailed Feedback
              </button>
            </div>
            
            {/* Scenario Progress */}
            <div className="bg-white rounded-xl shadow-sm p-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Scenario Progress</h3>
              <div className="space-y-4">
                <div className="flex items-center">
                  <div className="w-8 h-8 rounded-full bg-green-100 flex items-center justify-center mr-3">
                    <div className="w-3 h-3 rounded-full bg-green-500"></div>
                  </div>
                  <div>
                    <p className="font-medium text-gray-900">Opening Statements</p>
                    <p className="text-sm text-gray-500">Completed</p>
                  </div>
                </div>
                
                <div className="flex items-center">
                  <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center mr-3">
                    <div className="w-3 h-3 rounded-full bg-blue-500"></div>
                  </div>
                  <div>
                    <p className="font-medium text-gray-900">Evidence Presentation</p>
                    <p className="text-sm text-gray-500">In Progress</p>
                  </div>
                </div>
                
                <div className="flex items-center">
                  <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center mr-3">
                    <div className="w-3 h-3 rounded-full bg-gray-400"></div>
                  </div>
                  <div>
                    <p className="font-medium text-gray-900">Closing Arguments</p>
                    <p className="text-sm text-gray-500">Not Started</p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CourtroomSimulation;
